using System;
using System.Collections.Generic;
using System.Net.WebSockets;
using System.Text;
using System.Threading;
using System.Threading.Tasks;
using System.Web.Script.Serialization;
using GTA;

namespace ModProject
{
    public class Mod : Script
    {
        private enum ModState
        {
            Idle,
            Cooldown
        }

        private const int TargetGiftId = 5655;
        private const string TargetGiftName = "Rose";
        private const int CooldownSeconds = 30;
        private const int AmmoCount = 120;
        private const string WebSocketUrl = "ws://127.0.0.1:60080";

        private ModState _state;
        private DateTime _cooldownEnd;
        private ClientWebSocket _webSocket;
        private CancellationTokenSource _cancellationTokenSource;
        private readonly object _queueLock;
        private readonly Queue<Action> _actionQueue;
        private readonly JavaScriptSerializer _jsonSerializer;

        public Mod()
        {
            _state = ModState.Idle;
            _cooldownEnd = DateTime.MinValue;
            _queueLock = new object();
            _actionQueue = new Queue<Action>();
            _jsonSerializer = new JavaScriptSerializer();
            _cancellationTokenSource = new CancellationTokenSource();

            this.Tick += OnTick;
            this.Interval = 100;

            _webSocket = new ClientWebSocket();
            Task.Run(() => WebSocketLoop(_cancellationTokenSource.Token));
        }

        protected override void OnAbort()
        {
            _cancellationTokenSource.Cancel();
            try
            {
                _webSocket?.CloseAsync(WebSocketCloseStatus.NormalClosure, "Script abort", CancellationToken.None).Wait(2000);
            }
            catch
            {
            }
            _webSocket?.Dispose();
            _cancellationTokenSource?.Dispose();
            base.OnAbort();
        }

        private void OnTick(object sender, EventArgs e)
        {
            ProcessActionQueue();

            if (_state == ModState.Cooldown && DateTime.UtcNow >= _cooldownEnd)
            {
                _state = ModState.Idle;
            }
        }

        private void ProcessActionQueue()
        {
            List<Action> pendingActions = null;
            lock (_queueLock)
            {
                if (_actionQueue.Count > 0)
                {
                    pendingActions = new List<Action>(_actionQueue);
                    _actionQueue.Clear();
                }
            }

            if (pendingActions == null)
            {
                return;
            }

            foreach (Action action in pendingActions)
            {
                try
                {
                    action();
                }
                catch (Exception ex)
                {
                    GTA.UI.Notification.Show("~r~[Mod] Effect error: " + ex.Message);
                }
            }
        }

        private void EnqueueAction(Action action)
        {
            lock (_queueLock)
            {
                if (_actionQueue.Count < 50)
                {
                    _actionQueue.Enqueue(action);
                }
            }
        }

        private async Task WebSocketLoop(CancellationToken ct)
        {
            while (!ct.IsCancellationRequested)
            {
                try
                {
                    if (_webSocket.State != WebSocketState.Open)
                    {
                        await ConnectAsync(ct);
                    }

                    await ReceiveMessagesAsync(ct);
                }
                catch (OperationCanceledException)
                {
                    break;
                }
                catch (Exception)
                {
                    try
                    {
                        if (_webSocket.State == WebSocketState.Open || _webSocket.State == WebSocketState.CloseReceived)
                        {
                            await _webSocket.CloseAsync(WebSocketCloseStatus.ProtocolError, "Error", CancellationToken.None);
                        }
                    }
                    catch
                    {
                    }

                    _webSocket.Dispose();
                    _webSocket = new ClientWebSocket();
                    await Task.Delay(3000, ct);
                }
            }
        }

        private async Task ConnectAsync(CancellationToken ct)
        {
            await _webSocket.ConnectAsync(new Uri(WebSocketUrl), ct);

            string subscribeMessage = _jsonSerializer.Serialize(new Dictionary<string, object>
            {
                { "type", "serviceSignalSub" },
                { "service", "IM_MESSAGE_TRANSPORT" }
            });

            byte[] subscribeBytes = Encoding.UTF8.GetBytes(subscribeMessage);
            await _webSocket.SendAsync(new ArraySegment<byte>(subscribeBytes), WebSocketMessageType.Text, true, ct);
        }

        private async Task ReceiveMessagesAsync(CancellationToken ct)
        {
            byte[] buffer = new byte[8192];
            StringBuilder messageBuilder = new StringBuilder();

            while (_webSocket.State == WebSocketState.Open && !ct.IsCancellationRequested)
            {
                WebSocketReceiveResult result;
                messageBuilder.Clear();

                do
                {
                    result = await _webSocket.ReceiveAsync(new ArraySegment<byte>(buffer), ct);
                    if (result.MessageType == WebSocketMessageType.Close)
                    {
                        await _webSocket.CloseAsync(WebSocketCloseStatus.NormalClosure, "Server closed", CancellationToken.None);
                        return;
                    }

                    messageBuilder.Append(Encoding.UTF8.GetString(buffer, 0, result.Count));
                }
                while (!result.EndOfMessage);

                string rawJson = messageBuilder.ToString();
                ProcessJsonMessage(rawJson);
            }
        }

        private void ProcessJsonMessage(string rawJson)
        {
            try
            {
                Dictionary<string, object> message = _jsonSerializer.Deserialize<Dictionary<string, object>>(rawJson);
                if (message == null)
                {
                    return;
                }

                if (!message.TryGetValue("type", out object typeObj))
                {
                    return;
                }

                string messageType = typeObj as string;
                if (string.IsNullOrEmpty(messageType))
                {
                    return;
                }

                if (messageType == "WebcastGiftMessage")
                {
                    HandleGiftMessage(message);
                }
            }
            catch
            {
            }
        }

        private void HandleGiftMessage(Dictionary<string, object> message)
        {
            int giftId = -1;
            string giftName = null;

            if (message.TryGetValue("gift_id", out object idObj))
            {
                if (idObj is int idInt)
                {
                    giftId = idInt;
                }
                else if (idObj is string idStr && int.TryParse(idStr, out int parsedId))
                {
                    giftId = parsedId;
                }
            }
            else if (message.TryGetValue("giftId", out object idObj2))
            {
                if (idObj2 is int idInt)
                {
                    giftId = idInt;
                }
                else if (idObj2 is string idStr && int.TryParse(idStr, out int parsedId))
                {
                    giftId = parsedId;
                }
            }

            if (message.TryGetValue("gift_name", out object nameObj))
            {
                giftName = nameObj as string;
            }
            else if (message.TryGetValue("giftName", out object nameObj2))
            {
                giftName = nameObj2 as string;
            }

            bool isMatch = false;

            if (giftId == TargetGiftId)
            {
                isMatch = true;
            }
            else if (!string.IsNullOrEmpty(giftName) &&
                     string.Equals(giftName.Trim(), TargetGiftName, StringComparison.OrdinalIgnoreCase))
            {
                isMatch = true;
            }

            if (isMatch)
            {
                EnqueueAction(ExecuteRoseEffects);
            }
        }

        private void ExecuteRoseEffects()
        {
            if (_state == ModState.Cooldown)
            {
                return;
            }

            try
            {
                World.Weather = Weather.Raining;
            }
            catch
            {
            }

            try
            {
                Game.Player.WantedLevel = 4;
            }
            catch
            {
            }

            try
            {
                Ped playerPed = Game.Player.Character;
                if (playerPed != null && playerPed.Exists())
                {
                    playerPed.Weapons.Give(WeaponHash.SMG, AmmoCount, true, true);
                }
            }
            catch
            {
            }

            _state = ModState.Cooldown;
            _cooldownEnd = DateTime.UtcNow.AddSeconds(CooldownSeconds);

            GTA.UI.Notification.Show("~p~[Rose Gift] ~w~Rain + 4★ Wanted + SMG!");
        }
    }
}
